import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace } from "@tigrisdata/agent-kit";
import { put } from "@tigrisdata/storage";

const normalizeBucketName = (name: string) =>
  name
    .toLowerCase()
    .replace(/[^a-z0-9.-]+/g, "-")
    .replace(/^-+/, "")
    .replace(/-+$/, "");

const exitWithError = (message: string, error?: unknown): never => {
  if (error) {
    console.error(message, error);
  } else {
    console.error(message);
  }
  process.exit(1);
};

const run = async (): Promise<void> => {
  let trialId: string;
  try {
    trialId = (await readFile("/logs/artifacts/trial_id", "utf8")).trim();
  } catch (error) {
    exitWithError("Failed to read trial_id", error);
  }

  if (!trialId) {
    exitWithError("trial_id is empty");
  }

  const workspaceName = normalizeBucketName(`harbor-ws-${trialId}`);

  const { data: workspace, error: workspaceError } = await createWorkspace(
    workspaceName,
    {
      ttl: { days: 1 },
      credentials: { role: "Editor" },
    }
  );

  if (workspaceError) {
    exitWithError("Failed to create workspace", workspaceError);
  }

  if (!workspace || !workspace.credentials) {
    exitWithError("Workspace credentials missing");
  }

  const { accessKeyId, secretAccessKey } = workspace.credentials;
  if (!accessKeyId || !secretAccessKey) {
    exitWithError("Workspace credentials incomplete");
  }

  const payload = `{"status":"ok","run":"${trialId}"}`;

  const { error: putError } = await put("state.json", payload, {
    contentType: "application/json",
    config: {
      bucket: workspace.bucket,
      accessKeyId,
      secretAccessKey,
    },
  });

  if (putError) {
    exitWithError("Failed to upload state.json", putError);
  }

  try {
    await writeFile("/home/user/tigris-task/output.log", `${accessKeyId}\n`, "utf8");
  } catch (error) {
    exitWithError("Failed to write output.log", error);
  }

  console.log(accessKeyId);
};

run().catch((error) => exitWithError("Unexpected error", error));
